+        padding-top: 160px;
+        /* espacio para navbar de dos líneas */
+    }
+
+    /* ── About ── */
+    .about {
+        margin: var(--spacing-sm);
+        padding: var(--spacing-lg) var(--spacing-sm);
+        border-radius: 12px;
+    }
+
+    .about-content {
+        grid-template-columns: 1fr;
+        /* una sola columna */
+        gap: var(--spacing-lg);
+    }
+
+    /* Imagen va debajo del texto */
+
+
+    .about-text {
+        order: 1;
+    }
+
+    .about-image {
+        height: 350px;
+        overflow: hidden;
+    }
+
+    .about-content .about-image img {
+        max-width: 100%;
+        margin: 0 auto;
+        display: block;
+        border-radius: 12px;
+        object-fit: cover;
+        object-position: 0px -45px;
+        height: 100%;
+    }
+
+    .about-block-text p {
+        font-size: 0.95rem;
+    }
+
+    /* ── Carrusel de Skills ── */
+    .skills-carousel-continuous {
+        margin-top: var(--spacing-md);
+    }
+
+    .skills-track {
+        gap: var(--spacing-sm);
+        animation-duration: 28s;
+        /* un poco más rápido en mobile */
+    }
+
+    /* ~1.8 cards visibles en mobile */
+    .skills-carousel-continuous .skill-card {
+        flex: 0 0 160px;
+        min-width: 160px;
+        max-width: 160px;
+        padding: var(--spacing-sm);
+    }
+
+    .skill-card strong {
+        font-size: 0.95rem;
+    }
+
+    .skill-card p {
+        font-size: 0.8rem;
+    }
+
+    /* ── Experience / Timeline ── */
+    .experience {
+        padding: var(--spacing-xl) var(--spacing-sm);
+    }
+
+    /* En mobile la línea va a la izquierda, todo fluye en una columna */
+    .timeline::before {
+        left: 12px;
+        transform: none;
+    }
+
+    .timeline-item {
+        padding-left: 40px !important;
+        padding-right: 0 !important;
+        text-align: left !important;
+        margin-bottom: var(--spacing-lg);
+    }
+
+    .timeline-dot {
+        left: 3px;
+        transform: none;
+        width: 18px;
+        height: 18px;
+    }
+
+    .timeline-content {
+        padding: var(--spacing-sm);
+        border-radius: 8px;
+    }
+
+    .timeline-content h3 {
+        font-size: 1.05rem;
+    }
+
+    .timeline-content p {
+        font-size: 0.9rem;
+    }
+
+    /* ── Portfolio ── */
+    .portfolio {
+        padding: var(--spacing-xl) var(--spacing-sm);
+    }
+
+    .portfolio-grid {
+        grid-template-columns: 1fr 1fr;
+        gap: var(--spacing-sm);
+    }
+
+    /* ── Services ── */
+    .services {
+        padding: var(--spacing-xl) var(--spacing-sm);
+    }
+
+    .services-grid {
+        grid-template-columns: 1fr;
+        gap: var(--spacing-md);
+    }
+
+    /* ── Contact ── */
+    .contact {
+        padding: var(--spacing-xl) var(--spacing-sm);
+    }
+
+    /* ── Floating WhatsApp ── */
+    .floating-buttons {
+        bottom: var(--spacing-md);
+        right: var(--spacing-md);
+    }
+
+
+}
+
+
+/* ================================================================
+   RESPONSIVE — MOBILE PEQUEÑO  (≤ 480px)
+   ================================================================ */
+@media (max-width: 480px) {
+
+    .portfolio-grid {
+        grid-template-columns: 1fr;
+        /* una sola columna en pantallas muy pequeñas */
